const item = $input.first();
const data = item.json;

// Ensure an AI response exists
if (!data.output) {
    throw new Error("❌ AI output is missing.");
}

// Parse the AI's JSON string
let classification;

try {
    classification = JSON.parse(data.output);
} catch (error) {
    throw new Error("❌ AI output is not valid JSON.");
}

// Ensure the parsed value is an object
if (
    typeof classification !== "object" ||
    classification === null ||
    Array.isArray(classification)
) {
    throw new Error("❌ AI output is not a JSON object.");
}

// Ensure category exists
if (!Object.prototype.hasOwnProperty.call(classification, "category")) {
    throw new Error("❌ Missing 'category' field.");
}

// Ensure category is a string
if (typeof classification.category !== "string") {
    throw new Error("❌ 'category' must be a string.");
}

// Allowed categories
const allowedCategories = [
    "Work",
    "Personal",
    "Finance",
    "Promotions",
    "Spam"
];

// Validate category
if (!allowedCategories.includes(classification.category)) {
    throw new Error(
        `❌ Invalid category: ${classification.category}`
    );
}

// Success
return [{
    json: {
        ...data,

        aiClassification: classification,

        testResults: {
            ...(data.testResults ?? {}),
            v002: {
                passed: true,
                category: classification.category,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

