const item = $input.first();
const data = item.json;

// Ensure an AI response exists
if (!data.output) {
    throw new Error("❌ AI output is missing.");
}

// Parse the AI JSON
let classification;

try {
    classification = JSON.parse(data.output);
} catch (error) {
    throw new Error("❌ AI output is not valid JSON.");
}

// Ensure the parsed value is an object
if (
    typeof classification !== "object" ||
    classification === null ||
    Array.isArray(classification)
) {
    throw new Error("❌ AI output is not a JSON object.");
}

// Expected fields
const expectedFields = ["category", "folder"];

// Check for missing fields
for (const field of expectedFields) {
    if (!Object.prototype.hasOwnProperty.call(classification, field)) {
        throw new Error(`❌ Missing '${field}' field.`);
    }
}

// Check for unexpected fields
const extraFields = Object.keys(classification)
    .filter(key => !expectedFields.includes(key));

if (extraFields.length > 0) {
    throw new Error(
        `❌ Unexpected field(s): ${extraFields.join(", ")}`
    );
}

// Type validation
if (typeof classification.category !== "string") {
    throw new Error("❌ 'category' must be a string.");
}

if (typeof classification.folder !== "string") {
    throw new Error("❌ 'folder' must be a string.");
}

// Allowed mapping
const folderMap = {
    Work: "Work",
    Personal: "Personal",
    Finance: "Finance",
    Promotions: "Promotions",
    Spam: "Spam"
};

// Validate category
if (!Object.prototype.hasOwnProperty.call(folderMap, classification.category)) {
    throw new Error(
        `❌ Invalid category: ${classification.category}`
    );
}

// Validate folder
if (classification.folder !== folderMap[classification.category]) {
    throw new Error(
        `❌ Folder mismatch. Expected '${folderMap[classification.category]}', got '${classification.folder}'.`
    );
}

// Success
return [{
    json: {
        ...data,
        aiClassification: classification,
        testResults: {
            ...(data.testResults ?? {}),
            v004: {
                passed: true,
                contractValidated: true,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

const item = $input.first();
const data = item.json;

// Ensure an AI response exists
if (!data.output) {
    throw new Error("❌ AI output is missing.");
}

// Normalize the AI response
let cleanedOutput = data.output.trim();

// Remove Markdown code fences
cleanedOutput = cleanedOutput
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

// Parse normalized JSON
let classification;

try {
    classification = JSON.parse(cleanedOutput);
} catch (error) {
    throw new Error("❌ Normalized AI output is not valid JSON.");
}

// Ensure object
if (
    typeof classification !== "object" ||
    classification === null ||
    Array.isArray(classification)
) {
    throw new Error("❌ AI output is not a JSON object.");
}

return [{
    json: {
        ...data,

        // Preserve both versions
        rawAiOutput: data.output,
        normalizedAiOutput: cleanedOutput,

        aiClassification: classification,

        testResults: {
            ...(data.testResults ?? {}),
            v005: {
                passed: true,
                normalized: true,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

const item = $input.first();
const data = item.json;

// Ensure an AI response exists
if (!data.output) {
    throw new Error("❌ AI output is missing.");
}

// Preserve the original output
const rawOutput = data.output;

// Normalize the AI response
let normalizedOutput = rawOutput.trim();

// Remove Markdown code fences
normalizedOutput = normalizedOutput
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

// Parse normalized JSON
let classification;

try {
    classification = JSON.parse(normalizedOutput);
} catch (error) {
    throw new Error("❌ Failed to parse normalized AI output.");
}

// Ensure object
if (
    typeof classification !== "object" ||
    classification === null ||
    Array.isArray(classification)
) {
    throw new Error("❌ Normalized output is not a JSON object.");
}

// Success
return [{
    json: {
        ...data,

        rawAiOutput: rawOutput,
        normalizedAiOutput: normalizedOutput,
        aiClassification: classification,

        testResults: {
            ...(data.testResults ?? {}),
            v005: {
                passed: true,
                normalizationApplied: rawOutput !== normalizedOutput,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

const item = $input.first();
const data = item.json;

const classification = data.aiClassification;

if (!classification) {
    throw new Error("❌ Missing AI classification.");
}

const routes = {
    Work: "Work",
    Personal: "Personal",
    Finance: "Finance",
    Promotions: "Promotions",
    Spam: "Spam"
};

const destination = routes[classification.folder];

if (!destination) {
    throw new Error(`❌ No route defined for '${classification.folder}'.`);
}

return [{
    json: {
        ...data,

        routing: {
            destination,
            status: "READY"
        },

        version: "0.0.6"
    }
}];

const item = $input.first();
const data = item.json;

// Ensure routing object exists
if (!data.routing) {
    throw new Error("❌ Missing routing object.");
}

// Validate destination
if (!data.routing.destination) {
    throw new Error("❌ Missing routing destination.");
}

const validDestinations = [
    "Work",
    "Personal",
    "Finance",
    "Promotions",
    "Spam"
];

if (!validDestinations.includes(data.routing.destination)) {
    throw new Error(
        `❌ Invalid routing destination: ${data.routing.destination}`
    );
}

// Validate status
if (data.routing.status !== "READY") {
    throw new Error(
        `❌ Routing status expected 'READY' but received '${data.routing.status}'.`
    );
}

// Ensure routing agrees with the AI classification
if (
    data.aiClassification &&
    data.routing.destination !== data.aiClassification.folder
) {
    throw new Error(
        `❌ Routing destination '${data.routing.destination}' does not match AI folder '${data.aiClassification.folder}'.`
    );
}

// Success
return [{
    json: {
        ...data,

        testResults: {
            ...(data.testResults ?? {}),
            v006: {
                passed: true,
                destination: data.routing.destination,
                status: data.routing.status,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

