const item = $input.first();
const data = item.json;

// Ensure routing exists
if (!data.routing) {
    throw new Error("❌ Missing routing object.");
}

// Ensure action exists
if (!data.routing.action) {
    throw new Error("❌ Missing routing action.");
}

// Allowed actions
const validActions = [
    "MOVE_EMAIL",
    "LABEL_ONLY",
    "DELETE_EMAIL",
    "FORWARD_EMAIL",
    "FLAG_FOR_REVIEW"
];

if (!validActions.includes(data.routing.action)) {
    throw new Error(
        `❌ Invalid routing action: ${data.routing.action}`
    );
}

// Verify destination/action pair
const expectedActions = {
    Work: "MOVE_EMAIL",
    Personal: "MOVE_EMAIL",
    Finance: "MOVE_EMAIL",
    Promotions: "MOVE_EMAIL",
    Spam: "MOVE_EMAIL"
};

const expectedAction = expectedActions[data.routing.destination];

if (!expectedAction) {
    throw new Error(
        `❌ No expected action defined for destination '${data.routing.destination}'.`
    );
}

if (data.routing.action !== expectedAction) {
    throw new Error(
        `❌ Expected action '${expectedAction}' for destination '${data.routing.destination}', but received '${data.routing.action}'.`
    );
}

// Success
return [{
    json: {
        ...data,

        testResults: {
            ...(data.testResults ?? {}),
            v007: {
                passed: true,
                action: data.routing.action,
                destination: data.routing.destination,
                timestamp: new Date().toISOString()
            }
        }
    }
}];

