const item = $input.first();
const data = item.json;

// Ensure execution plan exists
if (!data.executionPlan) {
    throw new Error("❌ Missing execution plan.");
}

const plan = data.executionPlan;

// Validate provider
const validProviders = [
    "gmail"
];

if (!validProviders.includes(plan.provider)) {
    throw new Error(
        `❌ Invalid provider: ${plan.provider}`
    );
}

// Validate operation
const validOperations = [
    "MOVE_EMAIL",
    "LABEL_ONLY",
    "DELETE_EMAIL",
    "FORWARD_EMAIL",
    "FLAG_FOR_REVIEW"
];

if (!validOperations.includes(plan.operation)) {
    throw new Error(
        `❌ Invalid operation: ${plan.operation}`
    );
}

// Validate destination
const validDestinations = [
    "Work",
    "Personal",
    "Finance",
    "Promotions",
    "Spam"
];

if (!validDestinations.includes(plan.destination)) {
    throw new Error(
        `❌ Invalid destination: ${plan.destination}`
    );
}

// Validate readiness flags
if (plan.ready !== true) {
    throw new Error("❌ Execution plan is not marked as ready.");
}

if (plan.executed !== false) {
    throw new Error("❌ Execution plan should not already be executed.");
}

// Verify consistency with routing
if (data.routing) {
    if (plan.destination !== data.routing.destination) {
        throw new Error(
            `❌ Execution destination '${plan.destination}' does not match routing destination '${data.routing.destination}'.`
        );
    }

    if (plan.operation !== data.routing.action) {
        throw new Error(
            `❌ Execution operation '${plan.operation}' does not match routing action '${data.routing.action}'.`
        );
    }
}

// Success
return [{
    json: {
        ...data,

        testResults: {
            ...(data.testResults ?? {}),
            v008: {
                passed: true,
                provider: plan.provider,
                operation: plan.operation,
                destination: plan.destination,
                timestamp: new Date().toISOString()
            }
        }
    }
}];
